from flask import Flask
from pymongo import MongoClient

app = Flask(__name__)
client = MongoClient('localhost', 27017)
db = client['content_management_system']

@app.route('/')
def home():
    return 'Welcome to Content Management System'

@app.route('/user/<username>')
def get_user_profile(username):
    user_profile = db.users.find_one({'username': username})
    return str(user_profile)

@app.route('/documents')
def get_documents():
    documents = list(db.documents.find())
    return str(documents)

@app.route('/aggregate')
def aggregate_data():
    pipeline = [{ '$group': { '_id': '$category', 'total': { '$sum': 1 } } }]
    result = list(db.documents.aggregate(pipeline))
    return str(result)

if __name__ == '__main__':
    app.run(debug=True)